solutions.javascript:
// Solution
function solve(cssString) {
  const selectors = cssString.split('}');
  const animationDelays = [];
  const delayValues = {};
  for (const selector of selectors) {
    const match = selector.match(/selector([0-9]+):after {
      animation-delay: (.*)/);
    if (match) {
      const selectorName = match[1];
      const animationDelay = match[2];
      delayValues[selectorName] = animationDelay;
    }
  }
  const sortedDelayValues = Object.keys(delayValues).sort().map((selectorName) => delayValues[selectorName]);
  const output = selectors.join(', ') + ' {
    animation-delay: ' + sortedDelayValues.join(', ') + ';
  }';
  return output;
}

