class Solution:
  def solve(self, css_string: str) -> str:
    selectors = css_string.split('}');
    delay_values = {};
    for selector in selectors:
      match = selector.match(r'selector([0-9]+):after {
        animation-delay: (.*)');
      if match:
        selector_name = match[1];
        animation_delay = match[2];
        delay_values[selector_name] = animation_delay;

sorted_delay_values = [delay_values[selector_name] for selector_name in sorted(delay_values.keys())];
    output = ', '.join(selectors) + ' {
      animation-delay: ' + ', '.join(sorted_delay_values) + ';
    }';
    return output;

